terraform {

  backend "s3" {
    bucket = "terraform-state-meltwater-wrapidity-dev"
    key    = "k8s/service/groot.tfstate"
    region = "eu-west-1"
    encrypt = true
  }

  required_version = "~> 1.0"

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 3.0"
    }

    rabbitmq = {
      source = "cyrilgdn/rabbitmq"
      version = "1.8.0"
    }
  }

}

provider "kubernetes" {
  host                   = "https://api.ew1k8s2.prod.foundation.meltwater.io"
  cluster_ca_certificate = data.aws_kms_secrets.secrets.plaintext["kubernetes_cluster_ca_certificate"]
  token                  = data.aws_kms_secrets.secrets.plaintext["kubernetes_wrapidity_drone_token"]
}

provider "aws" {
  region = var.aws_region
  default_tags {
    tags = merge({
      Name       = "Groot",
      Service    = var.groot_name
    },
      var.common_tags)
  }
}

provider "rabbitmq" {
  endpoint = "https://${data.terraform_remote_state.rabbit.outputs.rabbit_host}"
  username = var.rabbit_username
  password = data.aws_kms_secrets.rabbit_secrets.plaintext["password"]
}

