# --- FKS -> EKS (Boron) migration ---------------------------------------------
# Non-secret Boron cluster coordinates, published in the Foundation EKS access
# reference. Defaults keep CI self-contained (the reusable Terraform workflow
# does not forward GHA org variables). Override per-run via
# TF_VAR_boron_k8s_api_server / TF_VAR_boron_k8s_ca_crt (GHA org vars
# BORON_K8S_API_SERVER / BORON_K8S_CA_CRT) if these coordinates ever change.
variable "boron_k8s_api_server" {
  description = "Boron (EKS non-prod) API server URL."
  default     = "https://86F20C107F6321B32C3C7491FB9CE77E.gr7.eu-west-1.eks.amazonaws.com"
}

variable "boron_k8s_ca_crt" {
  description = "Boron cluster CA certificate, base64-encoded (not secret)."
  default     = ""
}

variable "deploy_groot_boron" {
  description = "Feature flag: deploy the groot worker to Boron (EKS). Kept false until Boron prerequisites (KEDA, namespace, automation access, cross-VPC networking) are confirmed."
  type        = bool
  default     = false
}

